export type ActionPageFinanceBlockProps = {
  actionPage: PublicActionPage;
  donationCaption?: React.ReactNode;
  fundIdsOverride: string[];
  initialAmount: number;
  onSetAmount?: (amount?: number) => void;
  showLoadingOnAmounts?: boolean;
  totalFees: number;
  getPresetsForFrequency: (selectedFrequency: AmountPresetFrequency) => ActionPageFinancePreset[];
} & Pick<DonationSelectorProps, 'amounts' | 'frequencies' | 'showFundsAndAmounts'>;

export const ActionPageFinanceBlock = ({
  actionPage,
  getPresetsForFrequency,
  amounts,
  donationCaption,
  frequencies,
  fundIdsOverride,
  initialAmount,
  onSetAmount,
  showFundsAndAmounts,
  showLoadingOnAmounts,
  totalFees,
