  const { clearErrors, formState, setValue, trigger, watch } = useFormContext();
  const ticketAmount = useTicketTotalAmount(actionPage);
  // Events BE does not currently support recurring donations.
  // const selectedFrequency = watch('frequency') ?? frequencies?.[0];
  const selectedFrequency = SourceFrequency.Once;
  const amountAllocationsAttributes = watch('amountAllocationsAttributes') as AmountAllocation[];
  const otherAmount = watch('otherAmount');
  const productId = watch('productId');
  const donationAmount = useTotalAmount();
  const futurePledgeSelected = watch('futurePledgeSelected');
  const type = watch('type');
  const expressCheckoutMethod = watch('expressCheckoutMethod');

  const isBitcoinMethodSelected =
    expressCheckoutMethod === 'bitcoin_open_node' || type === 'bitcoin_open_node';

  const {
    amountConfiguration,
    designConfiguration,
    fundConfiguration,
    goaaEnabled,
    goaaForceSelection,
    goaaMinimumAmount,
    productPositionsAttributes,
    products,
    productsForRecurringOnly,
  } = actionPage;

  const amountsForSelectedFrequency = getPresetsForFrequency(selectedFrequency);

  const selectedAmount = useMemo(() => {
    return amountsForSelectedFrequency?.find(
      (a) => currency(a.amount!).intValue === donationAmount
    );
  }, [amounts, donationAmount]);

  const {
    amountPresetsOther,
    displayFrequencyAsCheckbox,
    transactionMaximum: transactionLimit,
    transactionMinimum: configurationTransactionMinimum,
  } = amountConfiguration || {};

  const { fundSelectionsAttributes, multiFundExpanded, multiFundModifiable } =
    fundConfiguration || {};
  const { actionElementColorPrimary: actionButtonBgColor } = designConfiguration;
  const actionButtonTextColor = useContrastColor(actionButtonBgColor);
  const actionButtonHoverBgColor = getShadeColor(actionButtonBgColor, -20);
  const onUpdateAmountAllocations = useCallback(
    (next: AmountAllocation[]) => {
      setValue('amountAllocationsAttributes', next);
    },
    [setValue]
  );

  const {
    addFund: addFundAllocation,
    additionalFunds,
    removeFund,
    selectedFunds,
  } = useFunds({
    amountAllocationsAttributes,
    fundIdsOverride,
    fundSelectionsAttributes,
    multiFundModifiable,
    onUpdateAmountAllocations,
  });

  const [showOtherInput, setShowOtherInput] = useState<boolean>(
    !amountsForSelectedFrequency ||
      (amountsForSelectedFrequency?.length === 0 && !!amountPresetsOther) ||
      (!!initialAmount &&
        !amountsForSelectedFrequency?.find(
          (x) => currency(`${x.amount}`).intValue === initialAmount
        ))
  );

  const availableProducts = useMemo(
    () =>
      goaaEnabled
        ? products?.sort(
            (a, b) =>
              (productPositionsAttributes?.find((p) => p.productId! === a.id)?.position || 0) -
              (productPositionsAttributes?.find((p) => p.productId! === b.id)?.position || 0)
          )
        : undefined,
    [goaaEnabled, productPositionsAttributes, products]
  );

  const selectedProduct = useMemo(
    () => availableProducts?.find(({ id }) => id === productId),
    [availableProducts, productId]
  );

  const setSelectedProduct = useCallback(
    (product) => setValue('productId', product?.id),
    [setValue]
  );

  const setSelectedFrequency = useCallback(
    (frequency: SourceFrequency) => {
      setValue('frequency', frequency);
    },
    [setValue]
  );

  const funds = useMemo(() => selectedFunds.map((x) => ({ ...x, ...x.fund })), [selectedFunds]);

  const fundsToShow = useMemo(
    () => funds.filter((x) => multiFundModifiable || (x.percentage ?? 0) > 0),
    [funds, multiFundModifiable]
  );

