  const shouldAutoBalanceOnAddOrSet = useMemo(
    () =>
      !fundsToShow?.length ||
      funds.reduce((total, fund) => (fund.percentage ?? 0) + total, 0) === 0,
    // Run once on mount
    []
  );

  const formIsValid = formState.isValid;
  const formHasErrors = useMemo(() => Object.keys(formState.errors).length > 0, [formState.errors]);
  const formWasSubmitted = formState.submitCount > 0;

  const setOtherAmount = useCallback(
    (amount = 0, balanceAmountAllocations = true, triggerCallback = true) => {
      if (selectedFunds.length > 0 && amount) {
        if (balanceAmountAllocations || shouldAutoBalanceOnAddOrSet) {
          const totalSelectedFundsPercentage = selectedFunds.reduce(
            (total, fnd) => total + (fnd?.percentage ?? 0),
            0
          );
          const newAmountAllocationsAttributes = selectedFunds.map((x) => ({
            actionPagesFundId: x.fund.id,
            amount: Math.round(
              (((shouldAutoBalanceOnAddOrSet || totalSelectedFundsPercentage < 100
                ? (1 / selectedFunds.length) * 100
                : (x.percentage ?? 0)) /
                100) *
                amount *
                100) /
                100
            ),
            fundType: x.type,
          }));

          // Check if we are short or over due to rounding and adjust using first fund
          const newTotal = newAmountAllocationsAttributes.reduce((acc, x) => acc + x.amount, 0);
          if (amount - newTotal > 0) {
            newAmountAllocationsAttributes[0].amount += amount - newTotal;
          } else if (amount - newTotal < 0) {
            newAmountAllocationsAttributes[0].amount += amount - newTotal;
          }

          setValue('amountAllocationsAttributes', newAmountAllocationsAttributes);
        }

        setValue('otherAmount', amount / 100);
      } else if (!amount) {
        setValue('amountAllocationsAttributes', []);
        setValue('otherAmount', 0);
      }

      if (triggerCallback) {
        onSetAmount?.(amount);
      }

      // if the form is in an invalid state due to a previous submission
      // trigger validation to try to
      // re-enable the donation button
      if (!formIsValid && formHasErrors && formWasSubmitted) {
        clearErrors();
        trigger();
      }
    },
    [
