      setShowOtherInput(false);
      if (amount) {
        setOtherAmount(currency(amount?.amount ?? 0).intValue);
      } else {
        setOtherAmount(0);
      }
    },
    [setOtherAmount]
  );

  const transactionMinimum = useMemo(
    () => (configurationTransactionMinimum || 0) / 100,
    [configurationTransactionMinimum]
  );

