      if (!shouldAutoBalanceOnAddOrSet || !fundSelection) {
        return;
      }

      const perFund = donationAmount / (amountAllocationsAttributes.length + 1);

      const newAmountAllocations = amountAllocationsAttributes.map((x) => ({
        ...x,
        amount: perFund,
