        actionPagesFundId,
        amount: perFund,
        fundType: fundSelection.type,
      });

      const nextOtherAmount = newAmountAllocations.reduce((a, b) => a + b.amount, 0) / 100;

      if (nextOtherAmount !== 0) {
        const presetAmount = (amountsForSelectedFrequency ?? []).find(
          (x) => currency(`${x.amount}`).intValue === otherAmount * 100
        );

        setShowOtherInput(!presetAmount);

