  //     setSelectedFrequency(frequencies[0]);
  //   }
  // }, [frequencies, selectedFrequency, setSelectedFrequency]);

  useEffect(() => {
    // Events BE does not currently support recurring donations.
    // if (!selectedFrequency) {
    //   setSelectedFrequency(frequencies[0]);
    // }

    // we only want to do this if we do not already have default amount allocation attributes
    const hasAmountsSet =
