  // Bitcoin can only be set to one-time donation
  //   if (isBitcoinMethodSelected) {
  //     setSelectedFrequency(SourceFrequency.Once);
  //   }
  // }, [isBitcoinMethodSelected, setSelectedFrequency]);

  useEffect(() => {
    setShowOtherInput(
      !amountsForSelectedFrequency ||
        (amountsForSelectedFrequency?.length === 0 && !!amountPresetsOther) ||
        (!!initialAmount &&
