      additionalFunds={additionalFunds.map((x) => ({ ...x, ...x.fund })) as DonationFundSelection[]}
      allowModificationsOfFunds={multiFundModifiable}
      amountAllocations={amountAllocationsAttributes}
      amountPresetsByFrequency={amountConfiguration?.amountPresets}
      amountPresetsOther={amountPresetsOther}
