      donationCaption={donationCaption}
      donationSelectorHeading={designConfiguration.donationSelectorHeading}
      donationSelectorHeadingOther={designConfiguration.donationSelectorHeadingOther}
      frequencies={frequencies}
      funds={funds as DonationFundSelection[]}
      futurePledgeDate={amountConfiguration?.futurePledgeDate}
      futurePledgeMessage={amountConfiguration?.futurePledgeMessage}
