      selectedFrequency={selectedFrequency}
      selectedProduct={selectedProduct}
      setAllocationAmount={(val) => setValue('amountAllocationsAttributes', val)}
      setFuturePledgeSelected={(val) => setValue('futurePledgeSelected', val)}
      setOtherAmount={setDonationSelectorOtherAmount}
      setSelectedAmount={setSelectedAmount}
      setSelectedFrequency={setSelectedFrequency}
      setSelectedProduct={setSelectedProduct}
      setShowOtherInput={setShowOtherInput}
      showFundsAndAmounts={showFundsAndAmounts}
      showLoadingOnAmounts={showLoadingOnAmounts}
      showOtherInput={showOtherInput}
      ticketAmount={ticketAmount}
      totalFees={totalFees}
